import{c as e,Q as a,j as o,m as r}from"./chunks/framework.BXc4yaFE.js";const h=JSON.parse('{"title":"A Good AGENTS.md is a Model Upgrade","description":"","frontmatter":{"url":"https://www.augmentcode.com/blog/how-to-write-good-agents-dot-md-files","title":"A Good AGENTS.md is a Model Upgrade","date":"2026-04-22T00:00:00.000Z","type":"article"},"headers":[],"relativePath":"research/ai-articles/scored/2026-04-22-agents-md-design-augment-code.md","filePath":"research/ai-articles/scored/2026-04-22-agents-md-design-augment-code.md","lastUpdated":1779894392000}'),l={name:"research/ai-articles/scored/2026-04-22-agents-md-design-augment-code.md"};function d(n,t,s,i,g,p){return a(),o("div",null,[...t[0]||(t[0]=[r(`<h1 id="a-good-agents-md-is-a-model-upgrade" tabindex="-1">A Good AGENTS.md is a Model Upgrade <a class="header-anchor" href="#a-good-agents-md-is-a-model-upgrade" aria-label="Permalink to &quot;A Good AGENTS.md is a Model Upgrade&quot;">​</a></h1><p><strong>作者</strong>: Slava Zhenylenko, Member of Technical Staff at Augment Code<br><strong>發布日期</strong>: 2026-04-22（更新：2026-04-23）<br><strong>來源</strong>: <a href="https://www.augmentcode.com/blog/how-to-write-good-agents-dot-md-files" target="_blank" rel="noreferrer">https://www.augmentcode.com/blog/how-to-write-good-agents-dot-md-files</a></p><h2 id="評分-5-維度" tabindex="-1">評分（5 維度） <a class="header-anchor" href="#評分-5-維度" aria-label="Permalink to &quot;評分（5 維度）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>得分</th><th>說明</th></tr></thead><tbody><tr><td>原創性</td><td>8/10</td><td>Augment Code 內部 eval 的數據驅動分析，指出 AGENTS.md 品質對 agent 表現的劇烈影響</td></tr><tr><td>實用性</td><td>9/10</td><td>7 種有效模式 + 失敗模式，直接對應 CLAUDE.md 設計理念</td></tr><tr><td>深度</td><td>8/10</td><td>有具體數字（25% 提升、30% 下降），但大多停留在高層觀點</td></tr><tr><td>清晰度</td><td>9/10</td><td>結構清晰，從問題、方案、反模式、應用都涵蓋</td></tr><tr><td>相關性</td><td>9/10</td><td>核心於 agents.md 設計，高度契合 workspace 架構實踐</td></tr><tr><td><strong>平均</strong></td><td><strong>8.6/10</strong></td><td><strong>強烈推薦收錄</strong></td></tr></tbody></table><hr><h2 id="核心洞見" tabindex="-1">核心洞見 <a class="header-anchor" href="#核心洞見" aria-label="Permalink to &quot;核心洞見&quot;">​</a></h2><h3 id="文件品質-模型升級" tabindex="-1">文件品質 = 模型升級 <a class="header-anchor" href="#文件品質-模型升級" aria-label="Permalink to &quot;文件品質 = 模型升級&quot;">​</a></h3><p>良寫的 AGENTS.md 相當於把模型從 Haiku 升級到 Opus；<br> 劣質的 AGENTS.md 比完全沒有文件還糟（效能 -30%）。</p><p><strong>含義</strong>: Context 與流程設計的重要性 <strong>超越模型選擇</strong>。</p><h3 id="七種有效模式" tabindex="-1">七種有效模式 <a class="header-anchor" href="#七種有效模式" aria-label="Permalink to &quot;七種有效模式&quot;">​</a></h3><ol><li><p><strong>漸進式揭示</strong> (Progressive Disclosure)</p><ul><li>主文件 100-150 行，聚焦核心規則</li><li>細節拆成參考文件（需時才讀）</li><li>效果：全指標 +10-15%</li></ul></li><li><p><strong>程序化工作流</strong> (Procedural Workflows)</p><ul><li>Step-by-step 任務描述</li><li>6 步部署流程例：正確性 +25%，完成度 +20%</li></ul></li><li><p><strong>決策表</strong> (Decision Tables)</p><ul><li>預先解決架構選擇（React Query vs Zustand）</li><li>約定俗成遵守度 +25%</li></ul></li><li><p><strong>生產程式碼例</strong> (Production Code Examples)</p><ul><li>3-10 行真實片段</li><li>程式碼重用率 +20%</li></ul></li><li><p><strong>領域特定規則</strong> (Domain-Specific Rules)</p><ul><li>語言、組織特殊約定</li><li>須具體且可執行</li></ul></li><li><p><strong>禁止配對解決方案</strong> (Pair Prohibitions with Solutions)</p><ul><li>不只說「不要 X」，要說「改用 Y」</li><li>避免 agent 過度謹慎</li></ul></li><li><p><strong>模組化文件</strong> (Modular Documentation)</p><ul><li>中規模模組（100 核心檔）用焦點文件勝過龐大倉庫級文件</li></ul></li></ol><h3 id="三大失敗模式" tabindex="-1">三大失敗模式 <a class="header-anchor" href="#三大失敗模式" aria-label="Permalink to &quot;三大失敗模式&quot;">​</a></h3><ol><li><p><strong>過度探索陷阱</strong> (Overexploration)</p><ul><li>原因：架構說明過多或 30+ 條警告規則</li><li>後果：Agent 載入不必要 context，完成度 -25%</li></ul></li><li><p><strong>模式不匹配</strong> (Mismatched Patterns)</p><ul><li>過時的架構決策導向錯誤實作</li></ul></li><li><p><strong>文件發現率差異</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>AGENTS.md: 100%</span></span>
<span class="line"><span>參考文件: 90%+</span></span>
<span class="line"><span>DIR README.md: 80%</span></span>
<span class="line"><span>嵌套文件: 40%</span></span>
<span class="line"><span>孤立 _docs/: &lt;10%</span></span></code></pre></div></li></ol><hr><h2 id="workspace-應用" tabindex="-1">Workspace 應用 <a class="header-anchor" href="#workspace-應用" aria-label="Permalink to &quot;Workspace 應用&quot;">​</a></h2><p><strong>直接對應 CLAUDE.md 現有設計</strong>：</p><table tabindex="0"><thead><tr><th>AGENTS.md 實踐</th><th>CLAUDE.md 對應</th></tr></thead><tbody><tr><td>漸進式揭示</td><td>常駐層 (@auto) + 按需層 (@skill) + 手動層 (Read)</td></tr><tr><td>決策表</td><td><code>.claude/rules/</code> 各檔案的決策樹</td></tr><tr><td>生產例</td><td><code>playbooks/</code> 中的 SRE runbooks</td></tr><tr><td>程序化工作流</td><td><code>/deep-review</code> Skill 的執行檢查表</td></tr><tr><td>禁止配對解決</td><td><code>core.md</code> §「外科刀式修改」對應的正確做法</td></tr></tbody></table><p><strong>洞見</strong>: AGENTS.md 質量不是「有最好」的附加，而是 <strong>負責任的 context engineering 必備</strong>。</p><hr><h2 id="引申思考" tabindex="-1">引申思考 <a class="header-anchor" href="#引申思考" aria-label="Permalink to &quot;引申思考&quot;">​</a></h2><h3 id="跨領域應用" tabindex="-1">跨領域應用 <a class="header-anchor" href="#跨領域應用" aria-label="Permalink to &quot;跨領域應用&quot;">​</a></h3><p>不只 coding agent：客服、營運、財務、法務 Agent 都需要等效的「工作說明書」。</p><blockquote><p>AGENTS.md 代表的本質：把資深同仁腦海裡的「做事默契」，轉化成 AI 可理解、可執行、可驗證的操作系統。</p></blockquote><h3 id="組織能力升級" tabindex="-1">組織能力升級 <a class="header-anchor" href="#組織能力升級" aria-label="Permalink to &quot;組織能力升級&quot;">​</a></h3><ul><li><strong>一階段</strong>: 買最強模型</li><li><strong>二階段</strong>: 升級 Agent 的工作環境設計</li><li><strong>未來</strong>: 企業差距不來自模型選擇，而來自誰更會設計「人與 Agent 共同工作的系統」</li></ul><hr><h2 id="評論" tabindex="-1">評論 <a class="header-anchor" href="#評論" aria-label="Permalink to &quot;評論&quot;">​</a></h2><p>Augment Code 的研究打破「模型 ≥ 一切」的直觀。核心發現是 <strong>context 結構化與流程清晰度</strong>對 agent 表現的舉足輕重。</p><p>特別有價值的：</p><ul><li><strong>數據化證據</strong> — 不只概念，有 +25% / -30% 的具體數字</li><li><strong>失敗模式詳列</strong> — 指出「看似努力的 over-exploration」陷阱</li><li><strong>文件發現率差異</strong> — 說明為何 AGENTS.md 必須在根目錄且高度焦點</li></ul><p><strong>主要限制</strong>：</p><ul><li>研究基於 Augment Code 自身 codebase（vendor content 色彩），不是跨組織普遍 eval</li><li>「好文件」的定義仍高度依賴專案類型（bug fix vs feature 的最優文件完全不同）</li></ul><p><strong>對 workspace 的啟發</strong>：CLAUDE.md 既有的三層載入、決策表、生產例模式已符合 Augment Code 研究的 7 種模式，印證架構設計方向。</p>`,33)])])}const u=e(l,[["render",d]]);export{h as __pageData,u as default};
